module top_module(Q, CLK, RST, LOAD, D);output [3:0] Q;
  input CLK, RST, LOAD;
  input [3:0] D;

  reg [3:0] invalid_count;

  always @(posedge CLK) begin
    if (RST) begin
      invalid_count <= 4'b0000;
    end
    else if (LOAD) begin
      invalid_count <= D;
    end
    else begin
      invalid_count <= invalid_count + 1;
    end
  end

  assign Q = invalid_count;

endmodule
